VALUES
  ('aboriginal-e3452428-moex-00461', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '依司法院大法官解釋意旨，下列何者非屬應以行政爭訟程序解決之爭議？', '["受刑人就不予假釋之決定，經向法務部提起復審，對復審結果仍表示不服", "林區管理處對於人民依據國有林地濫墾地補辦清理作業要點申請訂立租地契約未為准許之決定", "退役軍職人員與臺灣銀行訂立優惠存款契約後，由該契約衍生優惠存款利息給付爭議", "私立高中學生對於學校禁止其張貼海報，表示不服"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00462', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '下列何種情況不得依行政訴訟法提起確認訴訟？', '["臨檢措施已執行完畢", "集會遊行驅離措施已執行完畢", "違建已被拆除完畢且無回復原狀之可能", "候選人因資格不符遭主管機關否准參選且該選舉已辦理完畢"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00463', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於國家賠償法公共設施之國家賠償責任要件，下列敘述何者正確？', '["公共設施僅限人工構造物，山域、水域之自然公物不屬之", "於開放之山域、水域等自然公物內之設施，業經國家為適當之警告或標示者，國家即得不負損 害賠償責任", "私有公共設施供公眾使用，而國家處於事實上管理狀態者，亦適用國家賠償法", "公共設施未開放公用，人民擅自闖入致受損害，亦成立公共設施之國賠責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00464', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於公務員行為構成國家賠償責任之要件，下列敘述何者錯誤？', '["須行為違法", "須侵害人民之自由或權利", "須為行使公權力或私經濟行政行為", "須於執行職務時所為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00001', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'essay', '甲原住民持用合法登記有案之獵槍，經事前申請主管機關狩獵許可後，
於許可期間深夜前往該族之保留地狩獵野豬，甲尋覓一會之後，發現在
某大樹後方有一頭「野豬」，乃持獵槍瞄準後擊發子彈，子彈果然命中該
「野豬」，甲接著前往探視，才發現其實打中的不是野豬，而是同樣前往
保留地狩獵的另一位原住民乙，乙當時也以潛伏姿勢試圖獵捕野豬，因
山區夜間視線不佳，即使是富有經驗的原住民同族獵人，當下同樣無法
辨識，亦有非常高的機率發生相同誤會；乙因被甲所擊之子彈命中頭部
當場死亡。請問甲刑責為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00002', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'essay', '犯罪嫌疑人 A被控貪污罪，委任律師 B擔任辯護人。A到警局詢問製作
筆錄時，B在場陪同，但 B為處理其他當事人事件頻頻撥打手機，導致
警詢被多次中斷。製作筆錄的警察 C 多次勸阻 B停止使用手機，B 依然
如故，C 要求 B 離場。請分析 C 有無禁止 B 在場之權限，以及 B 對該
禁止在場處分如何救濟？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00003', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '關於「空白刑法」之補充法令的變更，依據實務見解，下列敘述何者正確？', '["屬法律變更，有刑法第2條第1項「從舊從輕原則」的適用", "屬法律變更，無刑法第2條第1項「從舊從輕原則」的適用", "非屬刑罰法律之變更，有刑法第2條第1項「從舊從輕原則」的適用", "非屬刑罰法律之變更，無刑法第2條第1項「從舊從輕原則」的適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00004', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲拿著一般垃圾打算投入資源垃圾專車，當場遭負責收取資源回收垃圾之區公所所屬清潔隊員A 阻止，甲一時惱羞成怒，竟辱罵A三字經，見A不為所動，甲隨即轉身離去。依實務見解，下列 敘述何者正確？', '["清潔隊員非屬公務員，甲之行為不成立侮辱公務員罪", "清潔隊員非屬公務員，甲之行為成立侮辱公務員罪", "清潔隊員係公務員，甲之行為不成立侮辱公務員罪", "清潔隊員係公務員，甲之行為應成立侮辱公務員罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00005', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲在市區以時速50公里超速行車（該路段速限為40公里），有機車騎士A突然違規左轉，甲煞 車不及撞傷A。事後經專業交通鑑定，因A係突然左轉、距離過近，事故發生當時縱使甲未超速， 也確定還是會煞車不及而撞傷A。下列敘述何者正確？', '["因甲超速行車才導致車禍發生讓A受傷，甲應成立過失傷害罪", "因A突然違規左轉才導致車禍發生，甲可主張信賴原則而無罪", "因A突然違規左轉才導致車禍發生，甲可主張容許風險而無罪", "因A受傷之結果客觀上無法避免，甲可主張欠缺相當因果關係而無罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00006', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲覬覦鄰居A之美貌圖謀不軌，在其主觀上認為口交係屬猥褻而非性交的情況下，為規避強制性 交罪之重刑，乃持刀脅迫A為其進行口交且既遂。關於甲應負之刑責，下列敘述何者正確？', '["口交係屬猥褻，甲主觀上亦具猥褻故意，應成立加重強制猥褻罪", "口交雖屬性交，但甲主觀上發生構成要件錯誤而阻卻其強制性交故意，仍僅成立加重強制猥褻罪", "口交雖屬性交，但甲主觀上發生包攝錯誤而阻卻其強制性交故意，不成立強制性交罪，僅構成 強制罪", "口交屬性交，甲主觀上雖發生包攝錯誤，但不影響其故意，甲仍成立加重強制性交罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
